-- V7: Seed large test data (1000 students, 1000 instructors, 1000 admins)

-- Seed 1000 Admins

SELECT id, (SELECT id FROM roles WHERE name = 'ROLE_ADMIN') FROM users WHERE username LIKE 'admin_%';

-- Seed 1000 Instructors

SELECT id, (SELECT id FROM roles WHERE name = 'ROLE_INSTRUCTOR') FROM users WHERE username LIKE 'instructor_%';

-- Seed 1000 Students

SELECT id, (SELECT id FROM roles WHERE name = 'ROLE_STUDENT') FROM users WHERE username LIKE 'student_%';

